#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int numbers[5], position, score = 0;
    char guess;
    for (int i = 0; i < 5; i++) numbers[i] = rand() % 10 + 1;
    printf("Numbers: ");
    for (int i = 0; i < 5; i++) {
        if (i == position - 1) printf("%d", numbers[i]);
        else printf("*");
    }
    printf("\nPick a number between 1 and 5, then enter 'E' or 'O': ");
    if (scanf("%d %c", &position, &guess) == 2) {
        score += 5;
        if ((numbers[position - 1] % 2 == 0 && guess == 'E') || 
            (numbers[position - 1] % 2 != 0 && guess == 'O')) {
            printf("win %d points\n", score);
        } else {
            printf("lose %d points\n", score);
        }
    }
    return 0;
}
